features.snippet:
struct { logic a; logic [7:0] b; } s;
always_comb begin s.a = 1'b0; end
always_ff @(posedge clk) begin s.b <= 8'd0; end

struct packed { logic en; logic [7:0] data; } st;
always_comb begin st.en = 1'b0; v = st.data; end
always_ff @(posedge clk) begin if(st.en) st.data <= st.data + 1; end
